// Extract messaging event from Meta webhook payload
const body = $input.first().json.body;

// Safely navigate the nested structure
const entry = body?.entry?.[0];
const messaging = entry?.messaging?.[0];

if (!messaging) {
  return [{ json: { skip: true, reason: 'no_messaging_event' } }];
}

// Skip non-message events (delivery, read receipts, echoes)
if (messaging.delivery || messaging.read) {
  return [{ json: { skip: true, reason: 'delivery_or_read_event' } }];
}

// Skip echo messages (messages sent BY the page)
if (messaging.message?.is_echo) {
  return [{ json: { skip: true, reason: 'echo_message' } }];
}

// Skip if no text message
if (!messaging.message?.text) {
  return [{ json: { skip: true, reason: 'no_text_message' } }];
}

// Extract sender PSID and message text
const senderPsid = messaging.sender.id;
const messageText = messaging.message.text;

return [{
  json: {
    skip: false,
    senderPsid: senderPsid,
    messageText: messageText,
    timestamp: messaging.timestamp
  }
}];

// Get the customer message from the extract step
const extractData = $('Is Valid Message?').first().json;
const customerMessage = extractData.messageText.toLowerCase();
const senderPsid = extractData.senderPsid;

// Get all products from Google Sheets
const products = $input.all().map(item => item.json);

// Filter: only Active products
const activeProducts = products.filter(p => 
  String(p.Active).toUpperCase() === 'YES'
);

// Search for matching products
const searchTerms = customerMessage
  .replace(/[^a-z0-9\s]/g, '')
  .split(/\s+/)
  .filter(word => word.length > 2)
  .filter(word => !['the','and','for','are','this','that','with','have','show','want','your','what','does','come','any','can','you','please','thanks','hello','much','how'].includes(word));

if (searchTerms.length === 0) {
  return [{
    json: {
      senderPsid: senderPsid,
      replyText: "I'd love to help you find something! Try asking about a product like:\n\n• \"Show me t-shirts\"\n• \"Do you have hoodies?\"\n• \"Black jeans in size 32\"\n• \"What do you have under $40?\"\n\nWhat are you looking for?",
      matchCount: 0
    }
  }];
}

// Score each product variant
const scored = activeProducts.map(product => {
  let score = 0;
  const searchableText = [
    product.Product_Name || '',
    product.Category || '',
    product.Description || '',
    product.Size || '',
    product.Color || '',
    product.Search_Keywords || ''
  ].join(' ').toLowerCase();

  for (const term of searchTerms) {
    if (searchableText.includes(term)) {
      score++;
    }
  }
  return { ...product, score };
});

// Filter products with score > 0
const matches = scored.filter(p => p.score > 0);

// Group by Product_ID
const grouped = {};
for (const match of matches) {
  const pid = match.Product_ID;
  if (!grouped[pid]) {
    grouped[pid] = {
      Product_ID: pid,
      Product_Name: match.Product_Name,
      Category: match.Category,
      Price: match.Price,
      Currency: match.Currency || 'USD',
      Description: match.Description,
      sizes: [],
      colors: [],
      inStockCount: 0,
      topScore: 0
    };
  }
  if (match.score > grouped[pid].topScore) {
    grouped[pid].topScore = match.score;
  }
  if (String(match.In_Stock).toUpperCase() === 'YES') {
    grouped[pid].inStockCount++;
    if (match.Size && !grouped[pid].sizes.includes(match.Size)) {
      grouped[pid].sizes.push(match.Size);
    }
    if (match.Color && !grouped[pid].colors.includes(match.Color)) {
      grouped[pid].colors.push(match.Color);
    }
  }
}

// Sort by score descending
const results = Object.values(grouped)
  .sort((a, b) => b.topScore - a.topScore)
  .slice(0, 5);

// Build reply
let replyText = '';

if (results.length === 0) {
  replyText = `I couldn't find any products matching "${customerMessage}".\n\nHere are our categories:\n• T-Shirts\n• Jeans\n• Hoodies\n• Dresses\n• Accessories\n\nTry asking something like "Show me hoodies" or "Black t-shirts in large".`;
} else {
  replyText = `I found ${results.length} product${results.length > 1 ? 's' : ''} for you:\n\n`;

  results.forEach((product, index) => {
    replyText += `${index + 1}. ${product.Product_Name} — $${product.Price}\n`;
    if (product.sizes.length > 0) {
      replyText += `   Sizes: ${product.sizes.join(', ')}\n`;
    }
    if (product.colors.length > 0) {
      replyText += `   Colors: ${product.colors.join(', ')}\n`;
    }
    if (product.inStockCount === 0) {
      replyText += `   ⚠️ Currently out of stock\n`;
    }
    replyText += '\n';
  });

  replyText += `Would you like to order any of these? Just tell me the product, size, and color!`;
}

return [{
  json: {
    senderPsid: senderPsid,
    replyText: replyText,
    matchCount: results.length
  }
}];
